INSERT INTO "about_sections" ("id", "title", "content", "image", "layout", "order", "created_at", "updated_at") VALUES ('1', 'Về Chúng Tôi', 'Chúng tôi là nền tảng đặt sân bóng trực tuyến hàng đầu tại Việt Nam, mang đến trải nghiệm đặt sân nhanh chóng, tiện lợi và đáng tin cậy.', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775986193/football-booking/about-sections/m7rpsiritzmz8ngeznje.jpg', 'image-left', '0', '2026-04-12 09:29:53', '2026-04-12 09:29:53');
INSERT INTO "about_sections" ("id", "title", "content", "image", "layout", "order", "created_at", "updated_at") VALUES ('3', 'Sứ Mệnh', 'Kết nối người chơi bóng đá với các sân bóng chất lượng, tạo điều kiện thuận lợi nhất cho việc tổ chức các trận đấu.', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775986218/football-booking/about-sections/fzta2ox3k3kcrx8whuew.jpg', 'image-right', '2', '2026-04-12 09:30:19', '2026-04-12 09:30:19');
INSERT INTO "about_sections" ("id", "title", "content", "image", "layout", "order", "created_at", "updated_at") VALUES ('4', 'Tầm Nhìn', 'Trở thành nền tảng đặt sân bóng số 1 Việt Nam, phục vụ hàng triệu người chơi bóng đá mỗi năm.', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775986250/football-booking/about-sections/lz2npdv7ssygxlvbespx.png', 'image-left', '3', '2026-04-12 09:30:50', '2026-04-12 09:30:50');
INSERT INTO "about_sections" ("id", "title", "content", "image", "layout", "order", "created_at", "updated_at") VALUES ('5', 'Gía trị cốt lõi', 'Tìm sân theo khu vực nhanh chóng Kiểm tra lịch trống realtime Đặt sân online, nhanh chóng Xem đánh giá sân trước khi đặt', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775986285/football-booking/about-sections/kqoab2o9lsmqpkpl421w.png', 'image-right', '4', '2026-04-12 09:31:26', '2026-04-12 09:31:26');
