INSERT INTO "owner_benefits" ("id", "title", "description", "image", "order", "created_at", "updated_at") VALUES ('1', 'Tăng Doanh Thu', 'Tiếp cận hàng nghìn khách hàng tiềm năng đang tìm kiếm sân bóng chất lượng mỗi ngày', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775987908/football-booking/owner-benefits/va6cpip6z7q5oz8s0uk2.jpg', '1', '2026-04-12 09:58:29', '2026-04-12 09:58:29');
INSERT INTO "owner_benefits" ("id", "title", "description", "image", "order", "created_at", "updated_at") VALUES ('2', 'Quản Lý Dễ Dàng', 'Hệ thống quản lý booking tự động, theo dõi lịch đặt sân và doanh thu realtime', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775987932/football-booking/owner-benefits/zumbii2qxcdtlmdvmoj6.jpg', '2', '2026-04-12 09:58:53', '2026-04-12 09:58:53');
INSERT INTO "owner_benefits" ("id", "title", "description", "image", "order", "created_at", "updated_at") VALUES ('3', 'Đa Nền Tảng', 'Quản lý sân bóng mọi lúc mọi nơi trên web và mobile, cập nhật tức thì', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775987982/football-booking/owner-benefits/qftrjb8pmngc1rhvwo0v.jpg', '3', '2026-04-12 09:59:43', '2026-04-12 09:59:43');
INSERT INTO "owner_benefits" ("id", "title", "description", "image", "order", "created_at", "updated_at") VALUES ('4', 'Marketing Miễn Phí', 'Sân của bạn được quảng bá rộng rãi trên nền tảng với hàng nghìn người dùng', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775988006/football-booking/owner-benefits/x8b5eidcb4xl8hitqiz6.jpg', '4', '2026-04-12 10:00:07', '2026-04-12 10:00:07');
INSERT INTO "owner_benefits" ("id", "title", "description", "image", "order", "created_at", "updated_at") VALUES ('5', 'Thanh Toán An Toàn', 'Hệ thống thanh toán bảo mật, đảm bảo quyền lợi cho bạn', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775988039/football-booking/owner-benefits/gigegs6iqt8um7fqhkre.jpg', '5', '2026-04-12 10:00:40', '2026-04-12 10:00:40');
INSERT INTO "owner_benefits" ("id", "title", "description", "image", "order", "created_at", "updated_at") VALUES ('6', 'Không cần giấy tờ phức tạp', 'Chúng tôi có hệ thống quản lý lưu trữ bằng các số liệu thật 100% giúp bạn không cần nhiều giấy tờ quản lý rườm rà', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775988180/football-booking/owner-benefits/dbujcaxrrcb8cgobhhza.jpg', '6', '2026-04-12 10:03:02', '2026-04-12 10:03:02');
INSERT INTO "owner_sections" ("id", "title", "content", "image", "image_position", "order", "created_at", "updated_at") VALUES ('2', 'Hỗ Trợ 24/7, Luôn Đồng Hành', 'Đội ngũ hỗ trợ chuyên nghiệp sẵn sàng giải đáp mọi thắc mắc và hỗ trợ kỹ thuật bất cứ lúc nào. Chúng tôi cam kết mang đến trải nghiệm tốt nhất cho đối tác của mình.', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775988407/football-booking/owner-sections/ysjrlfztjwic3dbpbtmb.jpg', 'left', '2', '2026-04-12 10:06:47', '2026-04-12 10:06:47');
INSERT INTO "owner_sections" ("id", "title", "content", "image", "image_position", "order", "created_at", "updated_at") VALUES ('1', 'Thống kê rõ ràng minh bạch', 'Chúng tôi cung cấp những thống kê thực tế, giúp bạn dễ dàng kiểm soát tài chỉnh', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775988385/football-booking/owner-sections/wfp4vwqmohmrfdfb1vd6.jpg', 'right', '1', '2026-04-12 10:06:25', '2026-04-12 10:06:53');
INSERT INTO "owner_sections" ("id", "title", "content", "image", "image_position", "order", "created_at", "updated_at") VALUES ('4', 'Tăng Trưởng Doanh Thu Bền Vững', 'Với hệ thống đặt sân trực tuyến hiện đại, chủ sân có thể tiếp cận hàng nghìn khách hàng tiềm năng mỗi ngày. Không còn lo lắng về sân trống, mọi khung giờ đều được tối ưu hóa để mang lại doanh thu cao nhất.', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775988462/football-booking/owner-sections/zeumng8nyuewjgnwmugk.jpg', 'left', '4', '2026-04-12 10:07:43', '2026-04-12 10:07:43');
INSERT INTO "owner_sections" ("id", "title", "content", "image", "image_position", "order", "created_at", "updated_at") VALUES ('3', 'Quản Lý Thông Minh, Tiết Kiệm Thời Gian', 'Dashboard quản lý trực quan giúp bạn theo dõi tất cả booking, doanh thu, và thống kê chi tiết chỉ trong một nơi. Tự động hóa quy trình đặt sân, giảm thiểu công việc thủ công và tập trung vào phát triển kinh doanh.', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775988433/football-booking/owner-sections/oeegqirnruboqx7ttoas.jpg', 'right', '3', '2026-04-12 10:07:14', '2026-04-12 10:07:50');
