INSERT INTO "tournaments" ("id", "owner_id", "field_id", "name", "description", "start_date", "end_date", "max_teams", "players_per_team", "entry_fee", "prize", "banner", "status", "created_at", "updated_at", "registration_deadline") VALUES ('3', '2', '4', 'Giải Futsal Cúp Mùa Xuân', 'Giải đấu Futsal 5 người chuyên nghiệp. Thể lệ thi đấu theo luật FIFA Futsal.', '2026-04-15', '2026-04-30', '8', '5', '300000.00', 'Vô địch: 3.000.000đ + Cúp Á quân: 2.000.000đ + Cúp Hạng 3: 1.000.000đ', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775990068/football-booking/tournaments/bgbvkatlutf8oajgkfwq.jpg', 'upcoming', '2026-04-12 10:34:29', '2026-04-12 10:34:29', '2026-04-14');
INSERT INTO "tournaments" ("id", "owner_id", "field_id", "name", "description", "start_date", "end_date", "max_teams", "players_per_team", "entry_fee", "prize", "banner", "status", "created_at", "updated_at", "registration_deadline") VALUES ('4', '2', '2', 'Giải bóng đá mùa hè 2026', 'Giải đấu bóng đá phong trào dành cho các đội nghiệp dư tại TP.HCM. Thi đấu theo thể thức vòng tròn một lượt, sau đó bán kết và chung kết.', '2026-07-12', '2026-07-31', '8', '5', '100000.00', 'Vô địch: 5.000.000đ + Cúp + Huy chương Á quân: 3.000.000đ + Cúp + Huy chương Hạng 3: 2.000.000đ + Huy chương Vua phá lưới: 500.000đ', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775990142/football-booking/tournaments/kqlta4iebm9thjcblsl4.jpg', 'upcoming', '2026-04-12 10:35:43', '2026-04-12 10:35:43', '2026-07-10');
INSERT INTO "tournaments" ("id", "owner_id", "field_id", "name", "description", "start_date", "end_date", "max_teams", "players_per_team", "entry_fee", "prize", "banner", "status", "created_at", "updated_at", "registration_deadline") VALUES ('1', '2', '1', 'Giải bóng đá Doanh nghiệp 2026', 'Giải đấu dành riêng cho các đội bóng của các doanh nghiệp, công ty tại khu vực. Tạo sân chơi lành mạnh, gắn kết nhân viên.', '2026-07-17', '2026-10-21', '8', '5', '10000.00', 'Vô địch: 10.000.000đ + Cúp + Huy chương Á quân: 6.000.000đ + Cúp + Huy chương Hạng 3: 3.000.000đ + Huy chương Hạng 4: 1.000.000đ', 'https://res.cloudinary.com/dcawwwu86/image/upload/v1775989919/football-booking/tournaments/hdmay1kd6etymjhqr2r0.jpg', 'upcoming', '2026-04-12 10:31:59', '2026-06-21 19:05:49', '2026-07-16');
